-- ============================================================
-- 02_SeedData.sql  –  Property Management System
-- ============================================================
-- NOTE: This project uses ASP.NET Core Identity, which hashes
-- passwords with PBKDF2. The seed data below uses the EXACT
-- password hashes generated by the C# SeedData.cs class at
-- first run (password policy: min 6 chars, 1 digit, 1 upper,
-- 1 lower). The authoritative seeder is SeedData.cs which
-- runs automatically on application startup.
--
-- This script provides equivalent reference data for:
--   a) a fresh manual database restore
--   b) documentation / assessment evidence
--
-- Credentials (same for local and Azure):
--   Manager  : manager@property.com   / Manager@123
--   Tenants  : ali@tenant.com         / Tenant@123
--              fatima@tenant.com      / Tenant@123
--              sara@tenant.com        / Tenant@123
--              ahmed@tenant.com       / Tenant@123
--   Staff    : ahmed@staff.com        / Staff@123
--              mohammed@staff.com     / Staff@123
--              yousif@staff.com       / Staff@123
--
-- RECOMMENDED USAGE:
--   Run 01_DatabaseSchema.sql first, then start the application.
--   SeedData.cs will populate all tables automatically using
--   UserManager<T> (correct password hashing + role assignment).
--   If you prefer a pure SQL restore, replace the PasswordHash
--   values below with hashes from your running instance by
--   querying: SELECT Email, PasswordHash FROM dbo.Users
-- ============================================================

-- ── Roles ────────────────────────────────────────────────────
-- These match the role names used throughout [Authorize(Roles="...")] attributes.

IF NOT EXISTS (SELECT 1 FROM [Roles] WHERE [Name] = 'PropertyManager')
    INSERT INTO [Roles] ([Id],[Name],[NormalizedName],[ConcurrencyStamp])
    VALUES (NEWID(),'PropertyManager','PROPERTYMANAGER',NEWID());

IF NOT EXISTS (SELECT 1 FROM [Roles] WHERE [Name] = 'Tenant')
    INSERT INTO [Roles] ([Id],[Name],[NormalizedName],[ConcurrencyStamp])
    VALUES (NEWID(),'Tenant','TENANT',NEWID());

IF NOT EXISTS (SELECT 1 FROM [Roles] WHERE [Name] = 'MaintenanceStaff')
    INSERT INTO [Roles] ([Id],[Name],[NormalizedName],[ConcurrencyStamp])
    VALUES (NEWID(),'MaintenanceStaff','MAINTENANCESTAFF',NEWID());

-- ── Buildings ────────────────────────────────────────────────
IF NOT EXISTS (SELECT 1 FROM [Buildings])
BEGIN
    SET IDENTITY_INSERT [Buildings] ON;
    INSERT INTO [Buildings] ([BuildingId],[Name],[Address],[Location],[TotalUnits]) VALUES
        (1, 'Al Seef Tower',   '12 Seef District, Manama',    'Seef',   10),
        (2, 'Zinj Residences', '45 Zinj Road, Manama',         'Zinj',    8),
        (3, 'Riffa View',      '78 Government Ave, Riffa',     'Riffa',  12);
    SET IDENTITY_INSERT [Buildings] OFF;
END

