    INSERT INTO [Units] ([UnitId],[BuildingId],[UnitNumber],[Type],[Bedrooms],[Bathrooms],[SizeInSqFt],[MonthlyRent],[Amenities],[AvailabilityStatus],[CurrentLeaseId]) VALUES
        (1,  1, '101', 'Apartment', 1, 1,  750,  280, 'Gym, Pool',                 'Available', NULL),
        (2,  1, '102', 'Apartment', 2, 2, 1100,  380, 'Gym, Pool, Parking',        'Occupied',  NULL),
        (3,  1, '103', 'Studio',    NULL, 1, 500, 190, 'Gym',                      'Available', NULL),
        (4,  2, '201', 'Apartment', 3, 2, 1400,  480, 'Parking, Storage',          'Occupied',  NULL),
        (5,  2, '202', 'Apartment', 2, 1,  950,  320, 'Parking',                   'Available', NULL),
        (6,  2, '203', 'Studio',    NULL, 1, 520, 200, NULL,                        'Available', NULL),
        (7,  3, '301', 'Villa',     4, 3, 2200,  750, 'Garden, Pool, Maid Room',   'Occupied',  NULL),
        (8,  3, '302', 'Apartment', 2, 2, 1050,  350, 'Balcony, Parking',          'Available', NULL),
        (9,  3, '303', 'Apartment', 1, 1,  800,  270, 'Balcony',                   'Available', NULL),
        (10, 1, '104', 'Apartment', 2, 2, 1050,  360, 'Gym, Pool, Concierge',      'Available', NULL);
    SET IDENTITY_INSERT [Units] OFF;
END

-- ── Note on Users ────────────────────────────────────────────
-- User accounts (manager, tenants, staff) are created by SeedData.cs
-- at application startup using ASP.NET Core Identity's UserManager.
-- Password hashes cannot be inserted as plain SQL because they include
-- a cryptographic salt generated at runtime.
--
-- To seed the database:
--   1. Run 01_DatabaseSchema.sql to create the schema.
--   2. Start the application (API project). SeedData.cs runs automatically.
--   3. All users, roles, leases, maintenance requests, payments, and
--      notifications are created on first startup.
--
-- After first startup you can export the seeded rows using:
--   SELECT * FROM [Users]
--   SELECT * FROM [UserRoles]
--   SELECT * FROM [Leases]
--   SELECT * FROM [MaintenanceRequests]
--   SELECT * FROM [Payments]

-- ── Verification query ────────────────────────────────────────
-- Run this after startup to confirm seeding succeeded:
SELECT
    u.[Email],
    u.[Discriminator] AS [UserType],
    r.[Name]          AS [Role]
FROM [Users] u
JOIN [UserRoles] ur ON u.[Id] = ur.[UserId]
JOIN [Roles]     r  ON r.[Id] = ur.[RoleId]
ORDER BY r.[Name], u.[Email];
